import React, { useState, useEffect, useCallback, useRef } from 'react';
import { GODDESS_DATA } from './constants';
import { Goddess } from './types';
import ButterflyOverlay from './components/ButterflyOverlay';
import PetalOverlay from './components/PetalOverlay';
import AtmosphereOverlay from './components/AtmosphereOverlay';
import SelectionBar from './components/SelectionBar';
import LocalAssetManager from './components/LocalAssetManager';
import InfoOverlay from './components/InfoOverlay';

type ActiveView = 'GODDESS' | 'ANGEL';
type InfoSection = 'NONE' | 'ABOUT' | 'NOTICE' | 'CUSTOM' | 'CONTACT';

const App: React.FC = () => {
  const [goddesses, setGoddesses] = useState<Goddess[]>(GODDESS_DATA);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isTransitioning, setIsTransitioning] = useState(false);
  const [showDetail, setShowDetail] = useState(false);
  const [showManager, setShowManager] = useState(false);
  const [activeView, setActiveView] = useState<ActiveView>('GODDESS');
  const [activeInfo, setActiveInfo] = useState<InfoSection>('NONE');
  const [mousePos, setMousePos] = useState({ x: 0.5, y: 0.5 });

  const selectedGoddess = goddesses[currentIndex];
  const isTransitioningRef = useRef(false);

  const performChange = useCallback((newIndex: number) => {
    if (isTransitioningRef.current) return;

    setIsTransitioning(true);
    isTransitioningRef.current = true;
    setShowDetail(false); 

    setTimeout(() => {
      setCurrentIndex(newIndex);
      setTimeout(() => {
        setIsTransitioning(false);
        isTransitioningRef.current = false;
      }, 50);
    }, 700);
  }, []);

  const handleGoddessChange = useCallback((g: Goddess) => {
    const newIndex = goddesses.findIndex(item => item.id === g.id);
    if (newIndex === currentIndex) return;
    performChange(newIndex);
  }, [currentIndex, goddesses, performChange]);

  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      setMousePos({
        x: e.clientX / window.innerWidth,
        y: e.clientY / window.innerHeight,
      });
    };
    window.addEventListener('mousemove', handleMouseMove);
    return () => window.removeEventListener('mousemove', handleMouseMove);
  }, []);

  useEffect(() => {
    const handleWheel = (e: WheelEvent) => {
      if (activeInfo !== 'NONE' || activeView !== 'GODDESS' || isTransitioningRef.current) return;
      if (Math.abs(e.deltaY) < 10) return;

      if (e.deltaY > 0) {
        const nextIndex = (currentIndex + 1) % goddesses.length;
        performChange(nextIndex);
      } else {
        const prevIndex = (currentIndex - 1 + goddesses.length) % goddesses.length;
        performChange(prevIndex);
      }
    };

    window.addEventListener('wheel', handleWheel, { passive: true });
    return () => window.removeEventListener('wheel', handleWheel);
  }, [currentIndex, goddesses.length, activeView, activeInfo, performChange]);

  const handleViewChange = (view: ActiveView) => {
    if (view === activeView || isTransitioningRef.current) return;
    setIsTransitioning(true);
    isTransitioningRef.current = true;
    setShowDetail(false);
    setTimeout(() => {
      setActiveView(view);
      setActiveInfo('NONE');
      setTimeout(() => {
        setIsTransitioning(false);
        isTransitioningRef.current = false;
      }, 50);
    }, 700);
  };

  const updateLocalUrl = (id: string, url: string) => {
    setGoddesses(prev => prev.map(g => g.id === id ? { ...g, localUrl: url } : g));
  };

  const isHundredFlowers = selectedGoddess.id === 'hundred-flowers';

  return (
    <div className={`relative w-screen h-screen transition-all duration-[1200ms] ${activeView === 'GODDESS' ? 'bg-[#030303]' : 'bg-[#08080a]'} text-[#e5e5e5] overflow-hidden select-none font-serif`}>
      {/* 装饰边框 */}
      <div className="absolute inset-16 border border-white/[0.03] pointer-events-none z-40 transition-opacity duration-1000" />

      {/* 背景层 */}
      <div className={`absolute inset-0 z-10 transition-all duration-1000 ease-in-out ${isTransitioning ? 'opacity-0 blur-2xl' : 'opacity-100 blur-0'}`}>
        <div className="relative w-full h-full overflow-hidden">
          <div 
            className="w-full h-full transition-transform duration-[6000ms] ease-out"
            style={{ transform: `scale(1.03) translate(${(mousePos.x - 0.5) * -20}px, ${(mousePos.y - 0.5) * -20}px)` }}
          >
            {activeView === 'GODDESS' ? (
              <img 
                key={selectedGoddess.localUrl || selectedGoddess.image}
                src={selectedGoddess.localUrl || selectedGoddess.image} 
                alt={selectedGoddess.name} 
                className={`w-full h-full object-cover transition-opacity duration-1000 ${isHundredFlowers ? 'opacity-60' : 'opacity-40'}`}
              />
            ) : (
              <div className="w-full h-full relative overflow-hidden bg-[#0c0c10]">
                <div className="absolute inset-0 opacity-[0.08] mix-blend-overlay pointer-events-none" 
                     style={{ backgroundImage: 'url("https://www.transparenttextures.com/patterns/asfalt-dark.png")' }} />
                <div className="absolute inset-0 bg-gradient-to-b from-black/60 via-transparent to-black/80" />
                <div className="absolute inset-x-0 bottom-0 h-2/3 bg-[radial-gradient(circle_at_50%_120%,rgba(255,255,255,0.08)_0%,transparent_70%)]" />
              </div>
            )}
          </div>
          <div className="absolute inset-0 vignette pointer-events-none" />
        </div>
      </div>

      {/* 粒子/环境层 */}
      <div className={`relative z-20 transition-opacity duration-1000 ${isTransitioning ? 'opacity-0' : 'opacity-100'}`}>
        {activeView === 'GODDESS' ? (
          <>
            {/* 核心改动：仅百花女神拥有粒子、花瓣、蝴蝶等特效系统 */}
            {isHundredFlowers && (
              <>
                <AtmosphereOverlay type={selectedGoddess.particleType} color={selectedGoddess.color} />
                <PetalOverlay type="general" color={selectedGoddess.color} />
                <ButterflyOverlay />
              </>
            )}
            {/* 十二花神部分：此处不再渲染任何粒子叠加层，保持画面静谧清爽 */}
          </>
        ) : (
          /* 天使卷环境：保持原有的圣光粒子 */
          <AtmosphereOverlay type="HOLY_LIGHT" color="#FFFFFF" />
        )}
      </div>

      <nav className="fixed left-16 top-1/2 -translate-y-1/2 z-50 flex flex-col gap-10">
        {[
          { id: 'ABOUT', label: '造境' },
          { id: 'NOTICE', label: '契约' },
          { id: 'CUSTOM', label: '灵筑' },
          { id: 'CONTACT', label: '传音' }
        ].map(item => (
          <button 
            key={item.id}
            onClick={() => setActiveInfo(item.id as InfoSection)}
            className="group flex flex-col items-center gap-4 transition-all"
          >
            <span className={`writing-v text-[10px] tracking-[0.6em] transition-all duration-500 ${activeInfo === item.id ? 'text-amber-500' : 'text-white/20 group-hover:text-white'}`}>
              {item.label}
            </span>
            <div className={`w-[1px] transition-all duration-700 ${activeInfo === item.id ? 'h-6 bg-amber-500 shadow-[0_0_8px_rgba(245,158,11,0.5)]' : 'h-3 bg-white/10 group-hover:h-6 group-hover:bg-white/20'}`} />
          </button>
        ))}
      </nav>

      <main className={`relative z-30 w-full h-full flex items-center pl-44 pr-40 transition-all duration-700 ${isTransitioning ? 'opacity-0' : 'opacity-100'}`}>
        {activeView === 'GODDESS' ? (
          <div key={selectedGoddess.id} className="w-full">
            <div className={`transition-all duration-700 ${showDetail ? 'translate-y-[-20px] scale-95 opacity-40 blur-sm' : 'translate-y-0 opacity-100'}`}>
              <div className="flex items-center gap-4 mb-4">
                <div className={`h-[1px] w-12 shadow-[0_0_5px_rgba(255,255,255,0.1)] ${isHundredFlowers ? 'bg-amber-500/50' : 'bg-white/10'}`} />
                <span className={`text-[9px] tracking-[0.5em] uppercase font-bold ${isHundredFlowers ? 'text-amber-500' : 'text-white/30'}`}>
                  {selectedGoddess.title}
                </span>
              </div>
              <h1 className={`font-brush text-5xl lg:text-7xl tracking-[0.1em] mb-8 drop-shadow-[0_10px_30px_rgba(0,0,0,0.5)] ${isHundredFlowers ? 'text-amber-100' : 'text-white'}`}>
                {selectedGoddess.name}
              </h1>
              <button 
                onClick={() => setShowDetail(true)}
                className="group flex items-center gap-4 py-2"
              >
                <div className="w-8 h-8 rounded-full border border-white/10 flex items-center justify-center group-hover:border-amber-500/50 transition-all duration-500">
                  <div className="w-1 h-1 bg-white/40 group-hover:bg-amber-500 group-hover:shadow-[0_0_8px_#f59e0b] rounded-full" />
                </div>
                <span className="text-[10px] tracking-[0.4em] text-white/20 group-hover:text-white transition-colors">阅 · 芳华录</span>
              </button>
            </div>

            {showDetail && (
              <div className="absolute inset-y-0 left-44 flex flex-col justify-center max-w-xl animate-fadeIn">
                <div className="flex flex-col gap-8 border-l border-amber-500/30 pl-10 backdrop-blur-sm py-6 pr-6 bg-black/5">
                  <p className="text-xl lg:text-2xl font-light text-white/90 leading-relaxed tracking-[0.2em] drop-shadow-md">
                    {selectedGoddess.shortDesc}
                  </p>
                  <p className="text-sm text-white/40 leading-[2.2] tracking-[0.15em] text-justify font-serif">
                    {selectedGoddess.description}
                  </p>
                  <button 
                    onClick={() => setShowDetail(false)}
                    className="mt-4 text-[9px] tracking-[0.5em] text-amber-500/60 hover:text-amber-500 uppercase w-fit border-b border-transparent hover:border-amber-500 transition-all pb-1"
                  >
                    [ 返回 / CLOSE ]
                  </button>
                </div>
              </div>
            )}
          </div>
        ) : (
          <div className="max-w-4xl mx-auto flex flex-col items-center text-center">
            <div className="mb-10 opacity-30 flex flex-col items-center gap-4">
               <div className="w-[1px] h-16 bg-gradient-to-t from-white to-transparent" />
               <div className="w-12 h-12 border border-white/40 rotate-45 flex items-center justify-center">
                  <div className="w-8 h-8 border border-white/20" />
               </div>
            </div>
            <h1 className="font-brush text-7xl lg:text-9xl text-white/90 mb-16 tracking-[0.4em] drop-shadow-[0_0_60px_rgba(255,255,255,0.15)]">天使系列</h1>
            <div className="relative flex flex-col items-center">
              <p className="text-xl lg:text-2xl italic font-light tracking-[0.6em] leading-[3] text-white/50 mb-16 max-w-3xl text-center">
                “凡人的晨曦尚未织就，<br/>在帕特农的穹顶之下，<br/>永恒的叹息，终将凝结成石材的呼吸。”
              </p>
              <div className="flex items-center justify-center gap-10 opacity-20">
                 <div className="w-24 h-[1px] bg-gradient-to-r from-transparent via-white to-transparent" />
                 <p className="text-[10px] tracking-[1.5em] uppercase font-bold text-white">SACRED PORTAL · 即将降临</p>
                 <div className="w-24 h-[1px] bg-gradient-to-l from-transparent via-white to-transparent" />
              </div>
            </div>
          </div>
        )}
      </main>

      <div className="fixed bottom-14 left-1/2 -translate-x-1/2 z-50 flex flex-col items-center gap-6">
        <span className="text-[8px] tracking-[0.8em] text-white/10 uppercase font-black">系列鉴赏 · THE SERIES</span>
        <div className="flex items-center gap-12 px-12 py-5 bg-white/[0.02] border border-white/5 backdrop-blur-3xl rounded-full shadow-[0_30px_60px_rgba(0,0,0,0.5)]">
          <button 
            onClick={() => handleViewChange('GODDESS')}
            className={`text-[11px] tracking-[0.6em] transition-all duration-500 ${activeView === 'GODDESS' ? 'text-amber-500 font-bold scale-105' : 'text-white/20 hover:text-white/50'}`}
          >
            花神卷
          </button>
          <div className="h-4 w-[1px] bg-white/10" />
          <button 
            onClick={() => handleViewChange('ANGEL')}
            className={`text-[11px] tracking-[0.6em] transition-all duration-500 ${activeView === 'ANGEL' ? 'text-amber-500 font-bold scale-105' : 'text-white/20 hover:text-white/50'}`}
          >
            天使卷
          </button>
        </div>
      </div>

      <InfoOverlay section={activeInfo} onClose={() => setActiveInfo('NONE')} />

      {activeView === 'GODDESS' && (
        <SelectionBar selectedId={selectedGoddess.id} allGoddesses={goddesses} onSelect={handleGoddessChange} />
      )}

      <footer className="fixed bottom-10 left-16 z-40 flex items-center gap-8 pointer-events-auto">
        <button onClick={() => setShowManager(true)} className="flex items-center gap-3 group opacity-20 hover:opacity-100 transition-opacity">
          <span className="text-[9px] tracking-[0.3em] font-bold uppercase">Mapping</span>
        </button>
        <div className="h-4 w-[1px] bg-white/10" />
        <span className="text-[8px] tracking-[0.5em] uppercase text-white/10">Visionary © 2024</span>
      </footer>

      <LocalAssetManager allGoddesses={goddesses} onUpload={updateLocalUrl} isOpen={showManager} onClose={() => setShowManager(false)} />
    </div>
  );
};

export default App;
